const DB_NAME = 'SiteInspectorDB';
const DB_VERSION = 1;

let db = null;

function openDb() {
    return new Promise((resolve, reject) => {
        if (db) { resolve(db); return; }
        const request = indexedDB.open(DB_NAME, DB_VERSION);
        request.onupgradeneeded = (e) => {
            const database = e.target.result;
            if (!database.objectStoreNames.contains('sites')) {
                database.createObjectStore('sites', { keyPath: 'id' });
            }
            if (!database.objectStoreNames.contains('inspections')) {
                const store = database.createObjectStore('inspections', { keyPath: 'id' });
                store.createIndex('siteId', 'siteId', { unique: false });
            }
            if (!database.objectStoreNames.contains('checklistItems')) {
                const store = database.createObjectStore('checklistItems', { keyPath: 'id' });
                store.createIndex('inspectionId', 'inspectionId', { unique: false });
            }
            if (!database.objectStoreNames.contains('photos')) {
                const store = database.createObjectStore('photos', { keyPath: 'id' });
                store.createIndex('inspectionId', 'inspectionId', { unique: false });
            }
        };
        request.onsuccess = (e) => { db = e.target.result; resolve(db); };
        request.onerror = (e) => reject(e.target.error);
    });
}

window.indexedDbFunctions = {
    initialize: async function () {
        await openDb();
        return true;
    },

    put: async function (storeName, item) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            const store = tx.objectStore(storeName);
            const request = store.put(item);
            request.onsuccess = () => resolve(true);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    get: async function (storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const store = tx.objectStore(storeName);
            const request = store.get(id);
            request.onsuccess = () => resolve(request.result || null);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getAll: async function (storeName) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const store = tx.objectStore(storeName);
            const request = store.getAll();
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getByIndex: async function (storeName, indexName, key) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const store = tx.objectStore(storeName);
            const index = store.index(indexName);
            const request = index.getAll(key);
            request.onsuccess = () => resolve(request.result);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    delete: async function (storeName, id) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readwrite');
            const store = tx.objectStore(storeName);
            const request = store.delete(id);
            request.onsuccess = () => resolve(true);
            request.onerror = (e) => reject(e.target.error);
        });
    },

    getPending: async function (storeName) {
        const database = await openDb();
        return new Promise((resolve, reject) => {
            const tx = database.transaction(storeName, 'readonly');
            const store = tx.objectStore(storeName);
            const request = store.getAll();
            request.onsuccess = () => {
                const pending = request.result.filter(item => item.syncStatus === 0);
                resolve(pending);
            };
            request.onerror = (e) => reject(e.target.error);
        });
    }
};

window.connectivityFunctions = {
    isOnline: function () {
        return navigator.onLine;
    },

    registerOnlineHandler: function (dotNetHelper) {
        window.addEventListener('online', () => {
            dotNetHelper.invokeMethodAsync('OnStatusChanged', true);
        });
        window.addEventListener('offline', () => {
            dotNetHelper.invokeMethodAsync('OnStatusChanged', false);
        });
    }
};

