            await TrySyncAsync();
        }
    }

    public async Task TrySyncAsync()
    {
        if (!_isOnline) return;

        try
        {
            var pendingSites = await _storage.GetPendingAsync<Site>("sites");
            foreach (var site in pendingSites)
            {
                try
                {
                    await _http.PostAsJsonAsync("/api/sites", site);
                    site.SyncStatus = SyncStatus.Synced;
                    await _storage.SaveSiteAsync(site);
                }
                catch { /* Will retry next cycle */ }
            }

            var pendingInspections = await _storage.GetPendingAsync<Inspection>("inspections");
            foreach (var inspection in pendingInspections)
            {
                try
                {
                    await _http.PostAsJsonAsync("/api/inspections", inspection);
                    inspection.SyncStatus = SyncStatus.Synced;
                    await _storage.SaveInspectionAsync(inspection);
                }
                catch { }
            }

            var pendingItems = await _storage.GetPendingAsync<ChecklistItem>("checklistItems");
            foreach (var item in pendingItems)
            {
                try
                {
                    await _http.PostAsJsonAsync("/api/checklist-items", item);
                    item.SyncStatus = SyncStatus.Synced;
                    await _storage.SaveChecklistItemAsync(item);
                }
                catch { }
            }

            var pendingPhotos = await _storage.GetPendingAsync<InspectionPhoto>("photos");
            foreach (var photo in pendingPhotos)
