+using Microsoft.JSInterop;
+using SiteInspector.Client.Models;
+using System.Text.Json;
+
+namespace SiteInspector.Client.Services;
+
+public class LocalStorageService
+{
+    private readonly IJSRuntime _js;
+    private static readonly JsonSerializerOptions JsonOptions = new()
+    {
+        PropertyNamingPolicy = JsonNamingPolicy.CamelCase
+    };
+
+    public LocalStorageService(IJSRuntime js)
+    {
+        _js = js;
+    }
+
+    public async Task InitializeAsync()
+    {
+        await _js.InvokeVoidAsync("indexedDbFunctions.initialize");
+    }
+
+    // Sites
+    public async Task SaveSiteAsync(Site site)
+    {
+        var obj = SerializeToObject(site);
+        await _js.InvokeVoidAsync("indexedDbFunctions.put", "sites", obj);
+    }
+
+    public async Task<List<Site>> GetAllSitesAsync()
+    {
+        var result = await _js.InvokeAsync<JsonElement>("indexedDbFunctions.getAll", "sites");
+        return DeserializeList<Site>(result);
+    }
+
+    public async Task<Site?> GetSiteAsync(string id)
+    {
+        var result = await _js.InvokeAsync<JsonElement?>("indexedDbFunctions.get", "sites", id);
+        return result.HasValue ? Deserialize<Site>(result.Value) : null;
+    }
+
+    // Inspections
+    public async Task SaveInspectionAsync(Inspection inspection)
+    {
+        var obj = SerializeToObject(inspection);
+        await _js.InvokeVoidAsync("indexedDbFunctions.put", "inspections", obj);
+    }
+
+    public async Task<List<Inspection>> GetInspectionsBySiteAsync(string siteId)
+    {
+        var result = await _js.InvokeAsync<JsonElement>("indexedDbFunctions.getByIndex", "inspections", "siteId", siteId);
+        return DeserializeList<Inspection>(result);
+    }
+
+    public async Task<Inspection?> GetInspectionAsync(string id)
+    {
+        var result = await _js.InvokeAsync<JsonElement?>("indexedDbFunctions.get", "inspections", id);
+        return result.HasValue ? Deserialize<Inspection>(result.Value) : null;
+    }
+
+    // Checklist Items
+    public async Task SaveChecklistItemAsync(ChecklistItem item)
+    {
+        var obj = SerializeToObject(item);
+        await _js.InvokeVoidAsync("indexedDbFunctions.put", "checklistItems", obj);
+    }
+
+    public async Task<List<ChecklistItem>> GetChecklistItemsByInspectionAsync(string inspectionId)
+    {
+        var result = await _js.InvokeAsync<JsonElement>("indexedDbFunctions.getByIndex", "checklistItems", "inspectionId", inspectionId);
+        return DeserializeList<ChecklistItem>(result);
+    }
+
+    // Photos
+    public async Task SavePhotoAsync(InspectionPhoto photo)
+    {
+        var obj = SerializeToObject(photo);
+        await _js.InvokeVoidAsync("indexedDbFunctions.put", "photos", obj);
+    }
+
+    public async Task<List<InspectionPhoto>> GetPhotosByInspectionAsync(string inspectionId)
+    {
+        var result = await _js.InvokeAsync<JsonElement>("indexedDbFunctions.getByIndex", "photos", "inspectionId", inspectionId);
+        return DeserializeList<InspectionPhoto>(result);
+    }
+
+    public async Task DeletePhotoAsync(string id)
+    {
+        await _js.InvokeVoidAsync("indexedDbFunctions.delete", "photos", id);
+    }
+
+    // Sync helpers
+    public async Task<List<T>> GetPendingAsync<T>(string storeName)
+    {
+        var result = await _js.InvokeAsync<JsonElement>("indexedDbFunctions.getPending", storeName);
+        return DeserializeList<T>(result);
+    }
+
+    private object SerializeToObject<T>(T item)
+    {
+        var json = JsonSerializer.Serialize(item, JsonOptions);
+        return JsonSerializer.Deserialize<object>(json, JsonOptions)!;
+    }
+
+    private T Deserialize<T>(JsonElement element)
+    {
+        return JsonSerializer.Deserialize<T>(element.GetRawText(), JsonOptions)!;
+    }
+
+    private List<T> DeserializeList<T>(JsonElement element)
+    {
+        return JsonSerializer.Deserialize<List<T>>(element.GetRawText(), JsonOptions) ?? new List<T>();
+    }
+}
+

