@page "/"
@inject LocalStorageService Storage

<div class="page-header">
    <h1>Construction Sites</h1>
</div>

@if (showAddForm)
{
    <div class="card">
        <div class="form-group">
            <label>Site Name</label>
            <input type="text" @bind="newSite.Name" placeholder="Enter site name" class="form-input" />
        </div>
        <div class="form-group">
            <label>Address</label>
            <input type="text" @bind="newSite.Address" placeholder="Enter address" class="form-input" />
        </div>
        <div class="button-row">
            <button class="btn btn-primary" @onclick="AddSite">Save Site</button>
            <button class="btn btn-secondary" @onclick="() => showAddForm = false">Cancel</button>
        </div>
    </div>
}
else
{
    <button class="btn btn-primary btn-full" @onclick="() => showAddForm = true">+ Add New Site</button>
}

<div class="site-list">
    @if (sites.Any())
    {
        @foreach (var site in sites)
        {
            <a class="card site-card" href="@($"site/{site.Id}/inspect")">
                <div class="site-name">@site.Name</div>
                <div class="site-address">@site.Address</div>
                <div class="sync-badge @(site.SyncStatus == SyncStatus.Synced ? "synced" : "pending")">
                    @(site.SyncStatus == SyncStatus.Synced ? "✓ Synced" : "⏳ Pending")
                </div>
            </a>
        }
    }
    else if (!showAddForm)
    {
        <div class="empty-state">
            <p>No sites yet. Add your first construction site.</p>
        </div>
    }
</div>

@code {
    private List<Site> sites = new();
    private Site newSite = new();
    private bool showAddForm;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            await Storage.InitializeAsync();
            sites = await Storage.GetAllSitesAsync();
        }
        catch { }
    }

    private async Task AddSite()
    {
        if (string.IsNullOrWhiteSpace(newSite.Name)) return;
        await Storage.SaveSiteAsync(newSite);
        sites.Add(newSite);
        newSite = new();
        showAddForm = false;
    }
}

@page "/site/{SiteId}/inspect"
@inject LocalStorageService Storage
@inject NavigationManager Nav

<div class="page-header">
    <button class="btn-back" @onclick="GoBack">← Back</button>
    <h1>@siteName</h1>
</div>

<div class="card">
    <h2>Start New Inspection</h2>
    <div class="form-group">
        <label>Inspector Name</label>
        <input type="text" @bind="inspectorName" placeholder="Your name" class="form-input" />
    </div>
    <button class="btn btn-primary btn-full" @onclick="StartInspection">Start Inspection</button>
</div>

<h2>Previous Inspections</h2>
<div class="inspection-list">
    @foreach (var inspection in inspections.OrderByDescending(i => i.StartedAt))
    {
        <a class="card inspection-card" href="@($"inspection/{inspection.Id}")">
            <div class="inspection-info">
                <strong>@inspection.InspectorName</strong>
                <span class="inspection-date">@inspection.StartedAt.ToLocalTime().ToString("MMM dd, yyyy HH:mm")</span>
            </div>
            <div class="status-badge @(inspection.Status == InspectionStatus.Completed ? "completed" : "in-progress")">
                @(inspection.Status == InspectionStatus.Completed ? "✓ Complete" : "In Progress")
            </div>
        </a>
    }
</div>

@code {
    [Parameter] public string SiteId { get; set; } = string.Empty;

    private string siteName = "Loading...";
    private string inspectorName = string.Empty;
    private List<Inspection> inspections = new();

    protected override async Task OnInitializedAsync()
    {
        await Storage.InitializeAsync();
        var site = await Storage.GetSiteAsync(SiteId);
        siteName = site?.Name ?? "Unknown Site";
        inspections = await Storage.GetInspectionsBySiteAsync(SiteId);
    }

    private async Task StartInspection()
    {
        if (string.IsNullOrWhiteSpace(inspectorName)) return;

        var inspection = new Inspection
        {
            SiteId = SiteId,
            InspectorName = inspectorName
        };
        await Storage.SaveInspectionAsync(inspection);

        // Create checklist items from template
        var templates = ChecklistTemplateService.GetTemplates();
        foreach (var (category, items) in templates)
        {
            foreach (var description in items)
            {
                var item = new ChecklistItem
                {
                    InspectionId = inspection.Id,
                    Category = category,
                    Description = description
                };
                await Storage.SaveChecklistItemAsync(item);
            }
        }

        Nav.NavigateTo($"inspection/{inspection.Id}");
    }

    private void GoBack() => Nav.NavigateTo("/");
}

@page "/inspection/{InspectionId}"
@inject LocalStorageService Storage
@inject NavigationManager Nav

<div class="page-header">
    <button class="btn-back" @onclick="GoBack">← Back</button>
    <h1>Inspection Checklist</h1>
</div>

@if (items.Any())
{
    <div class="progress-bar">
        <div class="progress-fill" style="width: @ProgressPercent%"></div>
    </div>
    <div class="progress-text">@CompletedCount / @items.Count checked</div>

    @foreach (var group in items.GroupBy(i => i.Category))
    {
        <div class="category-section">
            <h2 class="category-header">@group.Key</h2>
            @foreach (var item in group)
            {
                <div class="checklist-item">
                    <div class="item-description">@item.Description</div>
                    <div class="status-buttons">
                        <button class="status-btn @(item.Status == ChecklistStatus.Pass ? "active-pass" : "")"
                                @onclick="() => SetStatus(item, ChecklistStatus.Pass)">✓</button>
                        <button class="status-btn @(item.Status == ChecklistStatus.Fail ? "active-fail" : "")"
                                @onclick="() => SetStatus(item, ChecklistStatus.Fail)">✗</button>
                        <button class="status-btn @(item.Status == ChecklistStatus.NA ? "active-na" : "")"
                                @onclick="() => SetStatus(item, ChecklistStatus.NA)">N/A</button>
                    </div>
                    <div class="item-notes">
                        <input type="text" placeholder="Notes..." value="@item.Notes"
                               @onchange="(e) => UpdateNotes(item, e.Value?.ToString() ?? "")" class="note-input" />
                    </div>
                </div>
            }
        </div>
    }

    <div class="action-buttons">
        <a class="btn btn-secondary btn-full" href="@($"inspection/{InspectionId}/photos")">📷 Photos (@photoCount)</a>
        <a class="btn btn-primary btn-full" href="@($"inspection/{InspectionId}/summary")">View Summary</a>
    </div>
}
else
{
    <div class="empty-state"><p>Loading checklist...</p></div>
}

@code {
    [Parameter] public string InspectionId { get; set; } = string.Empty;

    private List<ChecklistItem> items = new();
    private int photoCount;

    private int CompletedCount => items.Count(i => i.Status != ChecklistStatus.NotChecked);
    private int ProgressPercent => items.Count > 0 ? (CompletedCount * 100 / items.Count) : 0;

    protected override async Task OnInitializedAsync()
    {
        await Storage.InitializeAsync();
        items = await Storage.GetChecklistItemsByInspectionAsync(InspectionId);
        var photos = await Storage.GetPhotosByInspectionAsync(InspectionId);
        photoCount = photos.Count;
    }

    private async Task SetStatus(ChecklistItem item, ChecklistStatus status)
    {
        item.Status = status;
        item.SyncStatus = SyncStatus.Pending;
        await Storage.SaveChecklistItemAsync(item);
    }

    private async Task UpdateNotes(ChecklistItem item, string notes)
    {
        item.Notes = notes;
        item.SyncStatus = SyncStatus.Pending;
        await Storage.SaveChecklistItemAsync(item);
    }

    private void GoBack()
    {
        Nav.NavigateTo("/");
    }
}

@page "/inspection/{InspectionId}/photos"
@inject LocalStorageService Storage
@inject NavigationManager Nav
@inject IJSRuntime JS

<div class="page-header">
    <button class="btn-back" @onclick="GoBack">← Back</button>
    <h1>Photos</h1>
</div>

<div class="card">
    <div class="form-group">
        <label>Capture Photo</label>
