+    protected override async Task OnInitializedAsync()
+    {
+        try
+        {
+            await Storage.InitializeAsync();
+            sites = await Storage.GetAllSitesAsync();
+        }
+        catch { }
+    }
+
+    private async Task AddSite()
+    {
+        if (string.IsNullOrWhiteSpace(newSite.Name)) return;
+        await Storage.SaveSiteAsync(newSite);
+        sites.Add(newSite);
+        newSite = new();
+        showAddForm = false;
+    }
