+@page "/inspection/{InspectionId}/photos"
+@inject LocalStorageService Storage
+@inject NavigationManager Nav
+@inject IJSRuntime JS
+
+<div class="page-header">
+    <button class="btn-back" @onclick="GoBack">← Back</button>
+    <h1>Photos</h1>
+</div>
+
+<div class="card">
+    <div class="form-group">
+        <label>Capture Photo</label>
+        <InputFile OnChange="HandleFileSelected" accept="image/*" capture="environment" class="file-input" />
+    </div>
+    <div class="form-group">
+        <label>Caption</label>
+        <input type="text" @bind="caption" placeholder="Describe the photo" class="form-input" />
+    </div>
+    @if (!string.IsNullOrEmpty(previewData))
+    {
+        <div class="photo-preview">
+            <img src="@previewData" alt="Preview" />
+        </div>
+        <button class="btn btn-primary btn-full" @onclick="SavePhoto">Save Photo</button>
+    }
+</div>
+
+<h2>Captured Photos (@photos.Count)</h2>
+<div class="photo-grid">
+    @foreach (var photo in photos)
+    {
+        <div class="photo-card">
+            <img src="@($"data:image/jpeg;base64,{photo.Base64Data}")" alt="@photo.Caption" />
+            <div class="photo-caption">@photo.Caption</div>
+            <div class="photo-time">@photo.CapturedAt.ToLocalTime().ToString("HH:mm")</div>
+            <button class="btn btn-danger btn-small" @onclick="() => DeletePhoto(photo)">Delete</button>
+        </div>
+    }
+</div>
+
+@code {
+    [Parameter] public string InspectionId { get; set; } = string.Empty;
+
+    private List<InspectionPhoto> photos = new();
+    private string caption = string.Empty;
+    private string previewData = string.Empty;
+    private string fileBase64 = string.Empty;
+    private string fileName = string.Empty;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await Storage.InitializeAsync();
+        photos = await Storage.GetPhotosByInspectionAsync(InspectionId);
+    }
+
+    private async Task HandleFileSelected(InputFileChangeEventArgs e)
+    {
+        var file = e.File;
+        if (file == null) return;
+
+        // Limit to 5MB
+        var maxSize = 5 * 1024 * 1024;
+        var buffer = new byte[file.Size > maxSize ? maxSize : file.Size];
+        await using var stream = file.OpenReadStream(maxSize);
+        await stream.ReadAsync(buffer);
+
+        fileBase64 = Convert.ToBase64String(buffer);
+        previewData = $"data:{file.ContentType};base64,{fileBase64}";
+        fileName = file.Name;
+    }
+
+    private async Task SavePhoto()
+    {
+        if (string.IsNullOrEmpty(fileBase64)) return;
+
+        var photo = new InspectionPhoto
+        {
+            InspectionId = InspectionId,
+            FileName = fileName,
+            Base64Data = fileBase64,
+            Caption = caption
+        };
+
+        await Storage.SavePhotoAsync(photo);
+        photos.Add(photo);
+
+        caption = string.Empty;
+        previewData = string.Empty;
+        fileBase64 = string.Empty;
+    }
+
+    private async Task DeletePhoto(InspectionPhoto photo)
+    {
+        await Storage.DeletePhotoAsync(photo.Id);
+        photos.Remove(photo);
+    }
+
+    private void GoBack() => Nav.NavigateTo($"inspection/{InspectionId}");
+}
+

