+@code {
+    private int pendingSites, pendingInspections, pendingChecklist, pendingPhotos;
+    private bool isSyncing;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await Storage.InitializeAsync();
+        await RefreshCounts();
+    }
+
+    private async Task RefreshCounts()
+    {
+        try
+        {
+            pendingSites = (await Storage.GetPendingAsync<Site>("sites")).Count;
+            pendingInspections = (await Storage.GetPendingAsync<Inspection>("inspections")).Count;
+            pendingChecklist = (await Storage.GetPendingAsync<ChecklistItem>("checklistItems")).Count;
+            pendingPhotos = (await Storage.GetPendingAsync<InspectionPhoto>("photos")).Count;
+        }
+        catch { }
+    }
+
+    private async Task SyncNow()
+    {
+        isSyncing = true;
+        StateHasChanged();
+        await SyncService.TrySyncAsync();
+        await RefreshCounts();
+        isSyncing = false;
+    }
+}
+

