}

.results-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 12px;
    margin-top: 12px;
}

.result-item {
    text-align: center;
    padding: 16px;
    border-radius: 8px;
}

.result-item.pass { background: #e8f5e9; }
.result-item.fail { background: #ffebee; }
.result-item.na { background: #f5f5f5; }
.result-item.unchecked { background: #fff3e0; }

.result-count {
    display: block;
    font-size: 32px;
    font-weight: 700;
}

.result-label {
    font-size: 13px;
    color: var(--text-secondary);
}

.failed-item {
    padding: 12px;
    border-left: 4px solid var(--danger);
    margin-bottom: 8px;
    background: #ffebee;
    border-radius: 0 8px 8px 0;
}

.item-note {
    font-size: 13px;
    color: var(--text-secondary);
    margin-top: 4px;
    font-style: italic;
}

/* Sync Page */
.connectivity-status {
    display: flex;
    align-items: center;
    gap: 12px;
    font-size: 18px;
    font-weight: 600;
}

.status-dot {
    width: 16px;
    height: 16px;
    border-radius: 50%;
}

.connectivity-status.online .status-dot { background: var(--success); }
.connectivity-status.offline .status-dot { background: var(--danger); }

.sync-counts {
    margin-top: 8px;
}

.sync-item {
    padding: 8px 0;
    border-bottom: 1px solid var(--border);
    font-size: 15px;
}

/* Empty State */
.empty-state {
    text-align: center;
    padding: 40px 16px;
    color: var(--text-secondary);
}

/* Disabled state */
button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}
