 using SiteInspector.Client.Models;
 using SiteInspector.Components;
 using System.Collections.Concurrent;

 var builder = WebApplication.CreateBuilder(args);

 builder.Services.AddRazorComponents()
     .AddInteractiveWebAssemblyComponents();

 var app = builder.Build();

 if (app.Environment.IsDevelopment())
 {
     app.UseWebAssemblyDebugging();
 }
 else
 {
     app.UseExceptionHandler("/Error", createScopeForErrors: true);
 }
 app.UseStatusCodePagesWithReExecute("/not-found", createScopeForStatusCodePages: true);
 app.UseAntiforgery();

 app.MapStaticAssets();

 // In-memory storage
 var sites = new ConcurrentDictionary<string, Site>();
 var inspections = new ConcurrentDictionary<string, Inspection>();
 var checklistItems = new ConcurrentDictionary<string, ChecklistItem>();
 var photos = new ConcurrentDictionary<string, InspectionPhoto>();

 // API endpoints
 app.MapGet("/api/sites", () => Results.Ok(sites.Values.ToList()));

 app.MapPost("/api/sites", (Site site) =>
 {
     sites[site.Id] = site;
     return Results.Ok(site);
 });

 app.MapPost("/api/inspections", (Inspection inspection) =>
 {
     inspections[inspection.Id] = inspection;
     return Results.Ok(inspection);
 });

 app.MapPost("/api/checklist-items", (ChecklistItem item) =>
 {
     checklistItems[item.Id] = item;
     return Results.Ok(item);
 });

 app.MapPost("/api/inspections/{inspectionId}/photos", (string inspectionId, InspectionPhoto photo) =>
 {
     photo.InspectionId = inspectionId;
     photos[photo.Id] = photo;
     return Results.Ok(photo);
 });

 app.MapPost("/api/sync", (SyncPayload payload) =>
 {
     foreach (var site in payload.Sites) sites[site.Id] = site;
     foreach (var inspection in payload.Inspections) inspections[inspection.Id] = inspection;
     foreach (var item in payload.ChecklistItems) checklistItems[item.Id] = item;
     foreach (var photo in payload.Photos) photos[photo.Id] = photo;
     return Results.Ok(new { synced = true });
 });

 app.MapRazorComponents<App>()
     .AddInteractiveWebAssemblyRenderMode()
     .AddAdditionalAssemblies(typeof(SiteInspector.Client._Imports).Assembly);

 app.Run();

 public class SyncPayload
 {
     public List<Site> Sites { get; set; } = new();
     public List<Inspection> Inspections { get; set; } = new();
     public List<ChecklistItem> ChecklistItems { get; set; } = new();
     public List<InspectionPhoto> Photos { get; set; } = new();
 }

